import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router } from '@angular/router';
import { Note } from '../../components/note-card/note-card.component';

@Component({
  selector: 'app-note-detail',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './note-detail.component.html',
  styleUrls: ['./note-detail.component.scss'],
})
export class NoteDetailComponent implements OnInit {
  note?: Note;
  loading = false;
  error = false;

  constructor(
    private route: ActivatedRoute,
    private router: Router,
  ) {}

  ngOnInit(): void {
    const noteId = this.route.snapshot.paramMap.get('id');
    if (noteId) {
      this.loadNote(noteId);
    } else {
      this.router.navigate(['/notes']);
    }
  }

  loadNote(id: string): void {
    this.loading = true;
    // Mock data por ahora
    setTimeout(() => {
      this.note = {
        id: id,
        titulo: 'Nota de Ejemplo',
        contenido: 'Este es el contenido detallado de la nota',
        tipo: 'text',
        etiquetas: 'ejemplo, prueba',
        archivada: false
      };
      this.loading = false;
    }, 500);
  }

  goBack(): void {
    this.router.navigate(['/notes']);
  }
}
<div class="note-detail-container">
  <div class="back-button">
    <button (click)="goBack()">← Volver</button>
  </div>

  <div class="note-content" *ngIf="!loading && !error && note; else loadingOrError">
    <h1>{{ note.titulo }}</h1>
    <p class="note-text">{{ note.contenido }}</p>

    <div class="note-meta">
      <span *ngIf="note.etiquetas">Etiquetas: {{ note.etiquetas }}</span>
      <span *ngIf="note.recordatorio">Recordatorio: {{ note.recordatorio | date:'medium' }}</span>
      <span *ngIf="note.archivada">Archivada</span>
    </div>
  </div>

  <ng-template #loadingOrError>
    <div class="loading" *ngIf="loading">
      <p>Cargando nota...</p>
    </div>
    <div class="error" *ngIf="error">
      <p>Error al cargar la nota</p>
    </div>
  </ng-template>
</div>
